import {
	buildDateFilter,
	escapeString,
	queryClickhouse,
} from "../clickhouse.js";

export interface DeveloperSummary {
	user_id: string;
	username?: string;
	total_sessions: number;
	active_days: number;
	total_tokens: number;
	total_duration_min: number;
	avg_session_duration_min: number;
	last_active_date: string;
	success_rate: number;
	cost: number;
	success_rate_trend: number;
	input_tokens: number;
	output_tokens: number;
}

export interface DeveloperDetails {
	user_id: string;
	username?: string;
	total_sessions: number;
	active_days: number;
	total_tokens: number;
	input_tokens: number;
	output_tokens: number;
	total_duration_min: number;
	avg_session_duration_min: number;
	last_active_date: string;
	success_rate: number;
	cost: number;
	success_rate_trend: number;
	distinct_projects: number;
	error_count: number;
}

export interface DeveloperSession {
	session_id: string;
	session_date: string;
	project_path: string;
	project_name?: string;
	duration_min: number;
	input_tokens: number;
	output_tokens: number;
	total_tokens: number;
	has_subagents: boolean;
	has_skills: boolean;
	has_slash_commands: boolean;
	has_errors: boolean;
	likely_success: boolean;
}

export interface DeveloperProject {
