/**
 * Get session analytics from the materialized view
 */
export async function getSessionAnalytics(
	orgId: string,
	params: {
		days?: number;
		user_id?: string;
		project_path?: string;
		repository?: string;
		limit?: number;
		offset?: number;
		sort_by?: "date" | "duration" | "interactions";
		sort_order?: "asc" | "desc";
	} = {},
): Promise<SessionAnalytics[]> {
	const {
		days = 30,
		user_id,
		project_path,
		repository,
		limit = 50,
		offset = 0,
		sort_by = "date",
		sort_order = "desc",
	} = params;

	const org = escapeString(orgId);
	const d = Number(days);
	const lim = Number(limit);
	const off = Number(offset);

	let filters = "";
	if (user_id) {
		filters += ` AND user_id = '${escapeString(user_id)}'`;
	}
	if (project_path) {
		filters += ` AND project_path = '${escapeString(project_path)}'`;
	}
	if (repository) {
		filters += ` AND repository = '${escapeString(repository)}'`;
	}

	const sortColumn =
		sort_by === "duration"
			? "actual_duration_min"
			: sort_by === "interactions"
				? "total_interactions"
				: "sa.session_date";
	const sortDirection = sort_order === "asc" ? "ASC" : "DESC";

	const query = `
    SELECT
      session_id,
      user_id,
      formatDateTime(sa.session_date, '%Y-%m-%d %H:%i:%S') as session_date,
      project_path,
      organization_id,
      repository,
      total_interactions,
      avg_period_sec,
      median_period_sec,
      quick_responses,
      normal_responses,
      long_pauses,
      actual_duration_min,
      formatDateTime(sa.last_interaction_date, '%Y-%m-%d %H:%i:%S') as last_interaction_date,
      total_tokens,
      input_tokens,
      output_tokens,
      git_sha,
      git_branch,
      has_commit,
      subagent_types,
      skills,
      slash_commands,
      session_archetype,
      success_score,
      error_count,
      model_used,
      used_plan_mode
    FROM rudel.session_analytics sa
    WHERE ${buildDateFilter(d, "sa.session_date")}
      AND organization_id = '${org}'
      ${filters}
    ORDER BY ${sortColumn} ${sortDirection}
    LIMIT ${lim}
    OFFSET ${off}
  `;

	const raw = await queryClickhouse<SessionAnalyticsRaw>(query);

	return raw.map(
		(row): SessionAnalytics => ({
			session_id: row.session_id,
			user_id: row.user_id,
			session_date: row.session_date,
			project_path: row.project_path,
			repository: row.repository || null,
			duration_min: row.actual_duration_min,
			total_tokens: row.total_tokens,
			input_tokens: row.input_tokens,
			output_tokens: row.output_tokens,
			success_score: row.success_score,
			total_interactions: row.total_interactions,
			avg_period_sec: row.avg_period_sec,
			subagent_types: row.subagent_types,
			skills: row.skills,
			slash_commands: row.slash_commands,
			has_commit: row.has_commit > 0,
			session_archetype: row.session_archetype,
			model_used: row.model_used,
			used_plan_mode: row.used_plan_mode > 0,
		}),
	);
}

