export async function getSessionAnalytics(
	orgId: string,
	params: {
		days?: number;
		user_id?: string;
		project_path?: string;
		repository?: string;
		limit?: number;
		offset?: number;
		sort_by?: "date" | "duration" | "interactions";
		sort_order?: "asc" | "desc";
	} = {},
): Promise<SessionAnalytics[]> {
	const {
		days = 30,
		user_id,
		project_path,
		repository,
		limit = 50,
		offset = 0,
		sort_by = "date",
		sort_order = "desc",
	} = params;

	const org = escapeString(orgId);
	const d = Number(days);
	const lim = Number(limit);
	const off = Number(offset);

	let filters = "";
	if (user_id) {
		filters += ` AND user_id = '${escapeString(user_id)}'`;
	}
	if (project_path) {
		filters += ` AND project_path = '${escapeString(project_path)}'`;
	}
	if (repository) {
		filters += ` AND repository = '${escapeString(repository)}'`;
	}

	const sortColumn =
		sort_by === "duration"
			? "actual_duration_min"
			: sort_by === "interactions"
				? "total_interactions"
				: "sa.session_date";
	const sortDirection = sort_order === "asc" ? "ASC" : "DESC";

	const query = `
    SELECT
      session_id,
      user_id,
      formatDateTime(sa.session_date, '%Y-%m-%d %H:%i:%S') as session_date,
      project_path,
      organization_id,
      repository,
