  1→import type { ErrorTrendDataPoint } from "@rudel/api-routes";
  2→import { useMemo } from "react";
  3→import {
  4→	Area,
  5→	AreaChart,
  6→	CartesianGrid,
  7→	Legend,
  8→	Line,
  9→	LineChart,
 10→	ResponsiveContainer,
 11→	Tooltip,
 12→	XAxis,
 13→	YAxis,
 14→} from "recharts";
 15→import { useChartTheme } from "@/hooks/useChartTheme";
 16→
 17→interface ErrorTrendChartProps {
 18→	data: ErrorTrendDataPoint[];
 19→	metric:
 20→		| "avg_errors_per_interaction"
 21→		| "avg_errors_per_session"
 22→		| "total_errors";
 23→	splitBy: "repository" | "user_id" | "model";
 24→	onMetricChange: (
 25→		metric:
 26→			| "avg_errors_per_interaction"
 27→			| "avg_errors_per_session"
 28→			| "total_errors",
 29→	) => void;
 30→	onSplitByChange: (splitBy: "repository" | "user_id" | "model") => void;
 31→	userMap?: Map<string, string>;
 32→}
 33→
 34→const COLORS = [
 35→	"#ef4444",
 36→	"#f59e0b",
 37→	"#10b981",
 38→	"#3b82f6",
 39→	"#8b5cf6",
 40→	"#ec4899",
 41→	"#06b6d4",
 42→	"#14b8a6",
 43→	"#f97316",
 44→	"#6366f1",
 45→];
 46→
 47→const METRIC_LABELS: Record<string, string> = {
 48→	avg_errors_per_interaction: "Avg Errors per Interaction",
 49→	avg_errors_per_session: "Avg Errors per Session",
 50→	total_errors: "Total Errors",
 51→};
 52→
 53→const SPLIT_LABELS: Record<string, string> = {
 54→	repository: "by Repository",
 55→	user_id: "by Developer",
 56→	model: "by Model",
 57→};
 58→
 59→export function ErrorTrendChart({
 60→	data,
 61→	metric,
 62→	splitBy,
 63→	onMetricChange,
 64→	onSplitByChange,
 65→	userMap,
 66→}: ErrorTrendChartProps) {
 67→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
 68→
 69→	const seriesKeys = useMemo(() => {
 70→		if (data.length === 0) return [];
 71→		const keys = new Set<string>();
 72→		for (const item of data) {
 73→			keys.add(item.dimension);
 74→		}
 75→		return Array.from(keys).sort();
 76→	}, [data]);
 77→
 78→	const chartData = useMemo(() => {
 79→		if (data.length === 0) return [];
 80→
 81→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
 82→		if (allDates.length === 0) return [];
 83→
 84→		const minDate = new Date(allDates[0]);
 85→		const maxDate = new Date(allDates[allDates.length - 1]);
 86→		const dateRange: string[] = [];
 87→
 88→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
 89→			dateRange.push(d.toISOString().split("T")[0]);
 90→		}
 91→
 92→		const dateMap = new Map<string, Record<string, unknown>>();
 93→
 94→		for (const dateKey of dateRange) {
 95→			const dateData: Record<string, unknown> = {
 96→				date: dateKey,
 97→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
 98→					month: "short",
 99→					day: "numeric",
100→				}),
101→			};
102→			for (const key of seriesKeys) {
103→				dateData[key] = 0;
104→			}
105→			dateMap.set(dateKey, dateData);
106→		}
107→
108→		for (const item of data) {
109→			const dateKey = item.date;
110→			if (dateMap.has(dateKey)) {
111→				const dateData = dateMap.get(dateKey)!;
112→				dateData[item.dimension] = item[metric];
113→			}
114→		}
115→
116→		return Array.from(dateMap.values()).sort((a, b) =>
117→			(a.date as string).localeCompare(b.date as string),
118→		);
119→	}, [data, metric, seriesKeys]);
120→
121→	const getDisplayName = (key: string): string => {
122→		if (splitBy === "user_id" && userMap) {
123→			return userMap.get(key) || `${key.substring(0, 12)}...`;
124→		}
125→		return key;
126→	};
127→
128→	return (
129→		<div className="space-y-4">
130→			<div className="flex flex-wrap items-center justify-between gap-4">
131→				<div className="flex items-center gap-2">
132→					<label className="text-sm font-medium text-muted">Metric:</label>
133→					<select
134→						value={metric}
135→						onChange={(e) => onMetricChange(e.target.value as typeof metric)}
136→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-56"
137→					>
138→						{Object.entries(METRIC_LABELS).map(([key, label]) => (
139→							<option key={key} value={key}>
140→								{label}
141→							</option>
142→						))}
143→					</select>
144→				</div>
145→
146→				<div className="flex items-center gap-2">
147→					<label className="text-sm font-medium text-muted">Split:</label>
148→					<select
149→						value={splitBy}
150→						onChange={(e) => onSplitByChange(e.target.value as typeof splitBy)}
151→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-40"
152→					>
153→						{Object.entries(SPLIT_LABELS).map(([key, label]) => (
154→							<option key={key} value={key}>
155→								{label}
156→							</option>
157→						))}
158→					</select>
159→				</div>
160→			</div>
161→
162→			<ResponsiveContainer width="100%" height={400}>
163→				{metric === "total_errors" ? (
164→					<AreaChart
165→						data={chartData}
166→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
167→					>
168→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
169→						<XAxis
170→							dataKey="displayDate"
171→							tick={{ fontSize: 12 }}
172→							angle={-45}
173→							textAnchor="end"
174→							height={80}
175→						/>
176→						<YAxis tick={{ fontSize: 12 }} />
177→						<Tooltip
178→							contentStyle={{
179→								backgroundColor: tooltipBg,
180→								border: `1px solid ${tooltipBorder}`,
181→								borderRadius: "8px",
182→								padding: "12px",
183→							}}
184→							formatter={(value, name) => {
185→								const displayName = name ? getDisplayName(String(name)) : "";
186→								return [((value as number) ?? 0).toLocaleString(), displayName];
187→							}}
188→							labelFormatter={(label) => `Date: ${label}`}
189→						/>
190→						<Legend
191→							formatter={(value) => getDisplayName(value)}
192→							wrapperStyle={{ fontSize: "12px" }}
193→						/>
194→						{seriesKeys.map((key, index) => (
195→							<Area
196→								key={key}
197→								type="monotone"
198→								dataKey={key}
199→								name={key}
200→								stackId="1"
201→								stroke={COLORS[index % COLORS.length]}
202→								fill={COLORS[index % COLORS.length]}
203→								fillOpacity={0.6}
204→							/>
205→						))}
206→					</AreaChart>
207→				) : (
208→					<LineChart
209→						data={chartData}
210→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
211→					>
212→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
213→						<XAxis
214→							dataKey="displayDate"
215→							tick={{ fontSize: 12 }}
216→							angle={-45}
217→							textAnchor="end"
218→							height={80}
219→						/>
220→						<YAxis tick={{ fontSize: 12 }} />
221→						<Tooltip
222→							contentStyle={{
223→								backgroundColor: tooltipBg,
224→								border: `1px solid ${tooltipBorder}`,
225→								borderRadius: "8px",
226→								padding: "12px",
227→							}}
228→							formatter={(value, name) => {
229→								const displayName = name ? getDisplayName(String(name)) : "";
230→								return [((value as number) ?? 0).toFixed(2), displayName];
231→							}}
232→							labelFormatter={(label) => `Date: ${label}`}
233→						/>
234→						<Legend
235→							formatter={(value) => getDisplayName(value)}
236→							wrapperStyle={{ fontSize: "12px" }}
237→						/>
238→						{seriesKeys.map((key, index) => (
239→							<Line
240→								key={key}
241→								type="monotone"
242→								dataKey={key}
243→								name={key}
244→								stroke={COLORS[index % COLORS.length]}
245→								strokeWidth={2}
246→								dot={{ r: 4 }}
247→								activeDot={{ r: 6 }}
248→								connectNulls={false}
249→							/>
250→						))}
251→					</LineChart>
252→				)}
253→			</ResponsiveContainer>
254→
255→			{seriesKeys.length === 0 && (
256→				<div className="text-center text-sm text-muted py-4">
257→					No error data available for the selected time period
258→				</div>
259→			)}
260→		</div>
261→	);
262→}
263→

  1→import { useCallback, useEffect, useRef, useState } from "react";
  2→import type { ConversationEntry } from "@/lib/conversation-schema";
  3→import { parseConversations } from "@/lib/conversation-schema";
  4→import { isSlashCommandMessage } from "@/lib/parse-slash-command";
  5→import { cn } from "@/lib/utils";
  6→import { ConversationMessage } from "./ConversationMessage";
  7→import type { TokenDataPoint } from "./TokenUsageChart";
  8→import type { ToolActivityPoint } from "./ToolActivityChart";
  9→
 10→interface ConversationViewProps {
 11→	content: string;
 12→	className?: string;
 13→	scrollContainerRef?: React.RefObject<HTMLElement | null>;
 14→	onActiveMessageChange?: (messageIndex: number) => void;
 15→	onTokenDataReady?: (data: TokenDataPoint[], totalMessages: number) => void;
 16→	onToolActivityReady?: (data: ToolActivityPoint[]) => void;
 17→	scrollToMessageIndex?: number | null;
 18→}
 19→
 20→/** Extract token usage data from parsed conversations */
 21→function extractTokenData(entries: ConversationEntry[]): TokenDataPoint[] {
 22→	const points: TokenDataPoint[] = [];
 23→
 24→	for (let i = 0; i < entries.length; i++) {
 25→		const entry = entries[i]!;
 26→		const entryAny = entry as Record<string, unknown>;
 27→
 28→		if (
 29→			("role" in entry && entry.role === "assistant") ||
 30→			("type" in entry && entryAny.type === "assistant")
 31→		) {
 32→			const message = entryAny.message as Record<string, unknown> | undefined;
 33→			const usage = message?.usage as Record<string, unknown> | undefined;
 34→
 35→			if (usage) {
 36→				points.push({
 37→					messageIndex: i,
 38→					inputTokens: (usage.input_tokens as number) || 0,
 39→					outputTokens: (usage.output_tokens as number) || 0,
 40→				});
 41→			}
 42→		}
 43→	}
 44→
 45→	return points;
 46→}
 47→
 48→/** Extract tool, skill, and subagent activity from parsed conversations */
 49→function extractToolActivity(
 50→	entries: ConversationEntry[],
 51→): ToolActivityPoint[] {
 52→	const points: ToolActivityPoint[] = [];
 53→
 54→	for (let i = 0; i < entries.length; i++) {
 55→		const entry = entries[i]!;
 56→		const entryAny = entry as Record<string, unknown>;
 57→
 58→		const isUser =
 59→			("role" in entry && entry.role === "user") ||
 60→			("type" in entry && entryAny.type === "user");
 61→
 62→		const isAssistant =
 63→			("role" in entry && entry.role === "assistant") ||
 64→			("type" in entry && entryAny.type === "assistant");
 65→
 66→		// User messages with toolUseResult → tool invocation result
 67→		if (isUser && entryAny.toolUseResult != null) {
 68→			const toolResult = entryAny.toolUseResult as Record<string, unknown>;
 69→			const toolType = (toolResult.type as string) || "tool";
 70→
 71→			const hasNonZeroExit =
 72→				typeof toolResult.code === "number" && toolResult.code !== 0;
 73→			const hasStderr =
 74→				typeof toolResult.stderr === "string" && toolResult.stderr.length > 0;
 75→			const wasInterrupted = toolResult.interrupted === true;
 76→
 77→			const content =
 78→				(entryAny.message as Record<string, unknown> | undefined)?.content ||
 79→				entryAny.content;
 80→			const contentHasError =
 81→				Array.isArray(content) &&
 82→				content.some((item: Record<string, unknown>) => item?.is_error);
 83→
 84→			const isError =
 85→				hasNonZeroExit || hasStderr || wasInterrupted || contentHasError;
 86→
 87→			// Check if this is a subagent (Task tool)
 88→			if (toolType === "Task") {
 89→				points.push({
 90→					messageIndex: i,
 91→					category: "subagent",
 92→					name: toolType,
 93→					isError,
 94→				});
 95→			} else {
 96→				points.push({
 97→					messageIndex: i,
 98→					category: "tool",
 99→					name: toolType,
100→					isError,
101→				});
102→			}
103→		}
104→
105→		// User messages with slash command content → skill
106→		if (isUser) {
107→			const content =
108→				(entryAny.message as Record<string, unknown> | undefined)?.content ||
109→				entryAny.content ||
110→				entryAny.text ||
111→				"";
112→			if (typeof content === "string" && isSlashCommandMessage(content)) {
113→				points.push({
114→					messageIndex: i,
115→					category: "skill",
116→					name: "slash-command",
117→					isError: false,
118→				});
119→			}
120→		}
121→
122→		// Assistant messages — scan content for tool_use items to capture Task/subagent launches
123→		if (isAssistant) {
124→			const message = entryAny.message as Record<string, unknown> | undefined;
125→			const content = (message?.content || entryAny.content) as
126→				| unknown[]
127→				| undefined;
128→
129→			if (Array.isArray(content)) {
130→				for (const block of content) {
131→					const b = block as Record<string, unknown>;
132→					if (b?.type === "tool_use" && b?.name === "Task") {
133→						const input = b.input as Record<string, unknown> | undefined;
134→						points.push({
135→							messageIndex: i,
136→							category: "subagent",
137→							name: (input?.subagent_type as string) || "Task",
138→							isError: false,
139→						});
140→					}
141→				}
142→			}
143→		}
144→	}
145→
146→	return points;
147→}
148→
149→export function ConversationView({
150→	content,
151→	className,
152→	scrollContainerRef,
153→	onActiveMessageChange,
154→	onTokenDataReady,
155→	onToolActivityReady,
156→	scrollToMessageIndex,
157→}: ConversationViewProps) {
158→	const [conversations, setConversations] = useState<ConversationEntry[]>([]);
159→	const [parseError, setParseError] = useState<string | null>(null);
160→	const messageRefsMap = useRef<Map<number, HTMLDivElement>>(new Map());
161→	const observerRef = useRef<IntersectionObserver | null>(null);
162→
163→	// Parse content
164→	useEffect(() => {
165→		if (!content || content.trim() === "") {
166→			setConversations([]);
167→			return;
168→		}
169→
170→		try {
171→			const lines = content.split("\n").filter((line) => line.trim() !== "");
172→
173→			const parsed = parseConversations(content);
174→
175→			if (parsed.length === 0 && lines.length > 0) {
176→				try {
177→					JSON.parse(lines[0]!);
178→					setParseError(
179→						`Failed to parse ${lines.length} conversation entries. Check console for details.`,
180→					);
181→				} catch {
182→					setParseError("Content is not valid JSONL format");
183→				}
184→			}
185→
186→			setConversations(parsed);
187→
188→			if (parsed.length > 0) {
189→				if (onTokenDataReady) {
190→					const tokenData = extractTokenData(parsed);
191→					onTokenDataReady(tokenData, parsed.length);
192→				}
193→				if (onToolActivityReady) {
194→					const activityData = extractToolActivity(parsed);
195→					onToolActivityReady(activityData);
196→				}
197→			}
198→		} catch (error) {
199→			console.error("[ConversationView] Error parsing conversations:", error);
200→			setParseError(error instanceof Error ? error.message : "Unknown error");
201→		}
202→	}, [content, onTokenDataReady, onToolActivityReady]);
203→
204→	// Set up IntersectionObserver for scroll tracking
205→	useEffect(() => {
206→		if (!onActiveMessageChange) return;
207→
208→		const root = scrollContainerRef?.current || null;
209→
210→		observerRef.current = new IntersectionObserver(
211→			(entries) => {
212→				let topmostIndex = -1;
213→				let topmostTop = Infinity;
214→
215→				for (const ioEntry of entries) {
216→					if (ioEntry.isIntersecting) {
217→						const idx = Number(
218→							ioEntry.target.getAttribute("data-message-index"),
219→						);
220→						if (
221→							!Number.isNaN(idx) &&
222→							ioEntry.boundingClientRect.top < topmostTop
223→						) {
224→							topmostTop = ioEntry.boundingClientRect.top;
225→							topmostIndex = idx;
226→						}
227→					}
228→				}
229→
230→				if (topmostIndex >= 0) {
231→					onActiveMessageChange(topmostIndex);
232→				}
233→			},
234→			{
235→				root,
236→				rootMargin: "0px 0px -80% 0px",
237→				threshold: 0,
238→			},
239→		);
240→
241→		for (const [, el] of messageRefsMap.current) {
242→			observerRef.current.observe(el);
243→		}
244→
245→		return () => {
246→			observerRef.current?.disconnect();
247→		};
248→	}, [onActiveMessageChange, scrollContainerRef]);
249→
250→	// Scroll to message when scrollToMessageIndex changes
251→	useEffect(() => {
252→		if (scrollToMessageIndex == null) return;
253→
254→		const el = messageRefsMap.current.get(scrollToMessageIndex);
255→		if (el) {
256→			el.scrollIntoView({ behavior: "smooth", block: "center" });
257→		}
258→	}, [scrollToMessageIndex]);
259→
260→	const registerMessageRef = useCallback(
261→		(index: number, el: HTMLDivElement | null) => {
262→			if (el) {
263→				messageRefsMap.current.set(index, el);
264→				observerRef.current?.observe(el);
265→			} else {
266→				const existing = messageRefsMap.current.get(index);
267→				if (existing) {
268→					observerRef.current?.unobserve(existing);
269→				}
270→				messageRefsMap.current.delete(index);
271→			}
272→		},
273→		[],
274→	);
275→
276→	if (parseError) {
277→		return (
278→			<div className={cn("py-8 text-center", className)}>
279→				<p className="text-red-600 dark:text-red-400 font-semibold mb-2">
280→					Error parsing conversation data
281→				</p>
282→				<p className="text-muted-foreground text-sm">{parseError}</p>
283→			</div>
284→		);
285→	}
286→
287→	if (conversations.length === 0) {
288→		return (
289→			<div className={cn("py-8 text-center", className)}>
290→				<p className="text-muted-foreground">No conversation data available</p>
291→			</div>
292→		);
293→	}
294→
295→	const conversationMessages = conversations.filter((entry) => {
296→		if ("role" in entry) return true;
297→		if ("type" in entry) {
298→			const type = (entry as Record<string, unknown>).type;
299→			return type === "user" || type === "assistant" || type === "system";
300→		}
301→		return false;
302→	});
303→
304→	const metadataEntries = conversations.filter((entry) => {
305→		if ("type" in entry) {
306→			const type = (entry as Record<string, unknown>).type;
307→			return (
308→				type === "file-history-snapshot" ||
309→				type === "progress" ||
310→				type === "queue-operation"
311→			);
312→		}
313→		return false;
314→	});
315→
316→	return (
317→		<div className={cn("space-y-6", className)}>
318→			<div className="text-xs text-muted-foreground mb-4">
319→				Showing {conversationMessages.length} messages
320→				{metadataEntries.length > 0 &&
321→					` (${metadataEntries.length} metadata entries hidden)`}
322→			</div>
323→			{conversations.map((entry, idx) => (
324→				<div
325→					key={idx}
326→					ref={(el) => registerMessageRef(idx, el)}
327→					data-message-index={idx}
328→				>
329→					<ConversationMessage entry={entry} messageIndex={idx} />
330→				</div>
331→			))}
332→		</div>
333→	);
334→}
