  1→import type {
  2→	Content,
  3→	TextContent,
  4→	ThinkingContent,
  5→	ToolResultContent,
  6→	ToolUseContent,
  7→} from "@/lib/conversation-schema";
  8→import { cn } from "@/lib/utils";
  9→import { CodeBlock } from "./CodeBlock";
 10→import { ToolInvocation } from "./ToolInvocation";
 11→
 12→interface MessageContentProps {
 13→	content: string | Content[];
 14→	className?: string;
 15→}
 16→
 17→// Parse code blocks from text content
 18→function parseTextContent(
 19→	text: string,
 20→): Array<{ type: "text" | "code"; content: string; language?: string }> {
 21→	const parts: Array<{
 22→		type: "text" | "code";
 23→		content: string;
 24→		language?: string;
 25→	}> = [];
 26→
 27→	// Match code blocks with language specifier: ```language\ncode\n```
 28→	const codeBlockRegex = /```(\w+)?\n([\s\S]*?)```/g;
 29→	let lastIndex = 0;
 30→	let match;
 31→
 32→	while ((match = codeBlockRegex.exec(text)) !== null) {
 33→		// Add text before code block
 34→		if (match.index > lastIndex) {
 35→			const textContent = text.slice(lastIndex, match.index).trim();
 36→			if (textContent) {
 37→				parts.push({ type: "text", content: textContent });
 38→			}
 39→		}
 40→
 41→		// Add code block
 42→		const language = match[1] || "text";
 43→		const code = match[2]!;
 44→		parts.push({ type: "code", content: code, language });
 45→
 46→		lastIndex = match.index + match[0].length;
 47→	}
 48→
 49→	// Add remaining text
 50→	if (lastIndex < text.length) {
 51→		const textContent = text.slice(lastIndex).trim();
 52→		if (textContent) {
 53→			parts.push({ type: "text", content: textContent });
 54→		}
 55→	}
 56→
 57→	// If no code blocks found, return the whole text
 58→	if (parts.length === 0 && text.trim()) {
 59→		parts.push({ type: "text", content: text.trim() });
 60→	}
 61→
 62→	return parts;
 63→}
 64→
 65→export function MessageContent({ content, className }: MessageContentProps) {
 66→	// Handle undefined or null content
 67→	if (!content) {
 68→		return (
 69→			<div className={cn("text-muted-foreground text-sm italic", className)}>
 70→				(No content)
 71→			</div>
 72→		);
 73→	}
 74→
 75→	// Handle string content
 76→	if (typeof content === "string") {
 77→		const parts = parseTextContent(content);
 78→
 79→		return (
 80→			<div className={cn("space-y-3", className)}>
 81→				{parts.map((part, idx) =>
 82→					part.type === "code" ? (
 83→						<CodeBlock key={idx} code={part.content} language={part.language} />
 84→					) : (
 85→						<div key={idx} className="prose prose-sm max-w-none">
 86→							<p className="whitespace-pre-wrap text-foreground leading-relaxed">
 87→								{part.content}
 88→							</p>
 89→						</div>
 90→					),
 91→				)}
 92→			</div>
 93→		);
 94→	}
 95→
 96→	// Handle non-array content (shouldn't happen, but be safe)
 97→	if (!Array.isArray(content)) {
 98→		return (
 99→			<div className={cn("text-muted-foreground text-sm italic", className)}>
100→				(Invalid content format: {typeof content})
101→			</div>
102→		);
103→	}
104→
105→	// Handle array of content blocks
106→	const toolUses = new Map<string, ToolUseContent>();
107→	const toolResults = new Map<string, ToolResultContent>();
108→
109→	// First pass: collect tool uses and results
110→	for (const block of content) {
111→		if (block.type === "tool_use") {
112→			toolUses.set(block.id, block);
113→		} else if (block.type === "tool_result") {
114→			toolResults.set(block.tool_use_id, block);
115→		}
116→	}
117→
118→	return (
119→		<div className={cn("space-y-3", className)}>
120→			{content.map((block, idx) => {
121→				switch (block.type) {
122→					case "text": {
123→						const textBlock = block as TextContent;
124→						const parts = parseTextContent(textBlock.text);
125→
126→						return (
127→							<div key={idx} className="space-y-3">
128→								{parts.map((part, partIdx) =>
129→									part.type === "code" ? (
130→										<CodeBlock
131→											key={partIdx}
132→											code={part.content}
133→											language={part.language}
134→										/>
135→									) : (
136→										<div key={partIdx} className="prose prose-sm max-w-none">
137→											<p className="whitespace-pre-wrap text-foreground leading-relaxed">
138→												{part.content}
139→											</p>
140→										</div>
141→									),
142→								)}
143→							</div>
144→						);
145→					}
146→
147→					case "thinking": {
148→						const thinkingBlock = block as ThinkingContent;
149→						return (
150→							<div
151→								key={idx}
152→								className="border-l-4 border-purple-300 dark:border-purple-800 bg-purple-50 dark:bg-purple-950 p-4 rounded-r"
153→							>
154→								<p className="text-xs font-semibold text-purple-700 dark:text-purple-300 mb-2">
155→									Internal Thinking
156→								</p>
157→								<p className="text-sm text-purple-900 dark:text-purple-100 whitespace-pre-wrap leading-relaxed italic">
158→									{thinkingBlock.thinking}
159→								</p>
160→							</div>
161→						);
162→					}
163→
164→					case "tool_use": {
165→						const toolUse = block as ToolUseContent;
166→						const toolResult = toolResults.get(toolUse.id);
167→
168→						return (
169→							<ToolInvocation
170→								key={idx}
171→								toolName={toolUse.name}
172→								input={toolUse.input}
173→								result={
174→									toolResult
175→										? {
176→												content: toolResult.content,
177→												is_error: toolResult.is_error,
178→											}
179→										: undefined
180→								}
181→							/>
182→						);
183→					}
184→
185→					case "tool_result": {
186→						// Skip standalone tool results (they're shown with tool_use blocks)
187→						const toolResult = block as ToolResultContent;
188→						// Only show if there's no matching tool_use
189→						if (!toolUses.has(toolResult.tool_use_id)) {
190→							const resultContent =
191→								typeof toolResult.content === "string"
192→									? toolResult.content
193→									: Array.isArray(toolResult.content)
194→										? toolResult.content
195→												.map((item) => item.text || JSON.stringify(item))
196→												.join("\n")
197→										: JSON.stringify(toolResult.content);
198→
199→							return (
200→								<div
201→									key={idx}
202→									className={cn(
203→										"border rounded-lg p-4",
204→										toolResult.is_error
205→											? "border-red-300 bg-red-50 dark:border-red-800 dark:bg-red-950"
206→											: "border-border bg-muted/30",
207→									)}
208→								>
209→									<p
210→										className={cn(
211→											"text-xs font-semibold mb-2",
212→											toolResult.is_error
213→												? "text-red-700 dark:text-red-300"
214→												: "text-muted-foreground",
215→										)}
216→									>
217→										{toolResult.is_error ? "Tool Error" : "Tool Result"}
218→									</p>
219→									<CodeBlock code={resultContent} language="text" />
220→								</div>
221→							);
222→						}
223→						return null;
224→					}
225→
226→					default:
227→						return null;
228→				}
229→			})}
230→		</div>
231→	);
232→}
