  1→import {
  2→	createContext,
  3→	type ReactNode,
  4→	useContext,
  5→	useEffect,
  6→	useState,
  7→} from "react";
  8→import { useSearchParams } from "react-router-dom";
  9→
 10→interface FilterContextType {
 11→	selectedDevelopers: string[];
 12→	selectedRepositories: string[];
 13→	setSelectedDevelopers: (developers: string[]) => void;
 14→	setSelectedRepositories: (repositories: string[]) => void;
 15→	clearAllFilters: () => void;
 16→	hasActiveFilters: boolean;
 17→}
 18→
 19→const FilterContext = createContext<FilterContextType | undefined>(undefined);
 20→
 21→const STORAGE_KEY = "globalFilters";
 22→
 23→const getInitialFilters = (searchParams: URLSearchParams) => {
 24→	const devsParam = searchParams.get("devs");
 25→	const reposParam = searchParams.get("repos");
 26→
 27→	if (devsParam || reposParam) {
 28→		return {
 29→			developers: devsParam ? devsParam.split(",").filter(Boolean) : [],
 30→			repositories: reposParam ? reposParam.split(",").filter(Boolean) : [],
 31→		};
 32→	}
 33→
 34→	try {
 35→		const stored = localStorage.getItem(STORAGE_KEY);
 36→		if (stored) {
 37→			const parsed = JSON.parse(stored);
 38→			return {
 39→				developers: parsed.developers || [],
 40→				repositories: parsed.repositories || [],
 41→			};
 42→		}
 43→	} catch {
 44→		// Ignore localStorage errors
 45→	}
 46→
 47→	return {
 48→		developers: [],
 49→		repositories: [],
 50→	};
 51→};
 52→
 53→export function FilterProvider({ children }: { children: ReactNode }) {
 54→	const [searchParams, setSearchParams] = useSearchParams();
 55→
 56→	const initialFilters = getInitialFilters(searchParams);
 57→	const [selectedDevelopers, setSelectedDevelopersInternal] = useState<
 58→		string[]
 59→	>(initialFilters.developers);
 60→	const [selectedRepositories, setSelectedRepositoriesInternal] = useState<
 61→		string[]
 62→	>(initialFilters.repositories);
 63→	const [isInitialized, setIsInitialized] = useState(false);
 64→
 65→	useEffect(() => {
 66→		const filters = getInitialFilters(searchParams);
 67→		setSelectedDevelopersInternal(filters.developers);
 68→		setSelectedRepositoriesInternal(filters.repositories);
 69→		setIsInitialized(true);
 70→		// biome-ignore lint/correctness/useExhaustiveDependencies: only run on mount
 71→	}, [searchParams]);
 72→
 73→	useEffect(() => {
 74→		if (!isInitialized) return;
 75→
 76→		try {
 77→			localStorage.setItem(
 78→				STORAGE_KEY,
 79→				JSON.stringify({
 80→					developers: selectedDevelopers,
 81→					repositories: selectedRepositories,
 82→				}),
 83→			);
 84→		} catch {
 85→			// Ignore localStorage errors
 86→		}
 87→
 88→		setSearchParams(
 89→			(prev) => {
 90→				if (selectedDevelopers.length > 0) {
 91→					prev.set("devs", selectedDevelopers.join(","));
 92→				} else {
 93→					prev.delete("devs");
 94→				}
 95→
 96→				if (selectedRepositories.length > 0) {
 97→					prev.set("repos", selectedRepositories.join(","));
 98→				} else {
 99→					prev.delete("repos");
100→				}
101→
102→				return prev;
103→			},
104→			{ replace: true },
105→		);
106→	}, [
107→		selectedDevelopers,
108→		selectedRepositories,
109→		isInitialized,
110→		setSearchParams,
111→	]);
112→
113→	const setSelectedDevelopers = (developers: string[]) => {
114→		setSelectedDevelopersInternal(developers);
115→	};
116→
117→	const setSelectedRepositories = (repositories: string[]) => {
118→		setSelectedRepositoriesInternal(repositories);
119→	};
120→
121→	const clearAllFilters = () => {
122→		setSelectedDevelopersInternal([]);
123→		setSelectedRepositoriesInternal([]);
124→	};
125→
126→	const hasActiveFilters =
127→		selectedDevelopers.length > 0 || selectedRepositories.length > 0;
128→
129→	return (
130→		<FilterContext.Provider
131→			value={{
132→				selectedDevelopers,
133→				selectedRepositories,
134→				setSelectedDevelopers,
135→				setSelectedRepositories,
136→				clearAllFilters,
137→				hasActiveFilters,
138→			}}
139→		>
140→			{children}
141→		</FilterContext.Provider>
142→	);
143→}
144→
145→export function useFilters() {
146→	const context = useContext(FilterContext);
147→	if (context === undefined) {
148→		throw new Error("useFilters must be used within a FilterProvider");
149→	}
150→	return context;
151→}
