123→					</label>
124→					<button
125→						id="cumulative-toggle"
126→						role="switch"
127→						aria-checked={isCumulative}
128→						onClick={() => setIsCumulative(!isCumulative)}
129→						className={`
130→							relative inline-flex h-6 w-11 items-center rounded-full transition-colors
131→							${isCumulative ? "bg-accent" : "bg-border"}
132→						`}
133→					>
134→						<span
135→							className={`
136→								inline-block h-4 w-4 transform rounded-full bg-input transition-transform
137→								${isCumulative ? "translate-x-6" : "translate-x-1"}
138→							`}
139→						/>
140→					</button>
141→				</div>
142→			</div>
143→
144→			<ResponsiveContainer width="100%" height={400}>
