148→				>
149→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
150→					<XAxis
151→						dataKey="displayDate"
152→						tick={{ fontSize: 12 }}
153→						angle={-45}
154→						textAnchor="end"
155→						height={80}
156→					/>
157→					<YAxis tick={{ fontSize: 12 }} />
158→					<Tooltip
159→						contentStyle={{
160→							backgroundColor: tooltipBg,
161→							border: `1px solid ${tooltipBorder}`,
162→							borderRadius: "8px",
163→							padding: "12px",
164→						}}
165→						formatter={(value, name) => {
166→							const displayName = name ? getDisplayName(String(name)) : "";
167→							return [((value as number) ?? 0).toLocaleString(), displayName];
168→						}}
169→						labelFormatter={(label) => `Date: ${label}`}
170→					/>
171→					<Legend
172→						formatter={(value) => getDisplayName(value)}
173→						wrapperStyle={{ fontSize: "12px" }}
174→					/>
175→					{seriesKeys.map((key, index) => (
176→						<Area
177→							key={key}
178→							type="monotone"
179→							dataKey={key}
180→							name={key}
181→							stackId="1"
182→							stroke={COLORS[index % COLORS.length]}
183→							fill={COLORS[index % COLORS.length]}
184→							fillOpacity={0.6}
185→						/>
186→					))}
187→				</AreaChart>
188→			</ResponsiveContainer>
189→
190→			{seriesKeys.length === 0 && (
191→				<div className="text-center text-sm text-muted py-4">
192→					No data available for the selected time period
193→				</div>
194→			)}
195→		</div>
196→	);
197→}
