 82→		return acc;
 83→	}, new Map<string, number>());
 84→
 85→	const topProjects = Array.from(projectTotals.entries())
 86→		.sort((a, b) => b[1] - a[1])
 87→		.slice(0, maxProjects)
 88→		.map(([path]) => path);
 89→
 90→	const filteredData = data.filter((d) => topProjects.includes(d.project_path));
 91→	const allDates = Array.from(new Set(filteredData.map((d) => d.date))).sort();
