155→						<XAxis
156→							dataKey="displayDate"
157→							stroke={axisStroke}
158→							style={{ fontSize: "12px" }}
159→							angle={-45}
160→							textAnchor="end"
161→							height={80}
162→						/>
163→						<YAxis
164→							stroke={axisStroke}
165→							style={{ fontSize: "12px" }}
166→							tickFormatter={currentMetric.formatter}
167→							domain={[0, 100]}
168→						/>
169→						<Tooltip
170→							contentStyle={{
171→								backgroundColor: tooltipBg,
172→								border: `1px solid ${tooltipBorder}`,
173→								borderRadius: "8px",
174→								padding: "12px",
175→							}}
176→							formatter={(value, name) => {
177→								if (!name || name === "date" || name === "displayDate")
178→									return null;
179→								return [
180→									currentMetric.formatter((value as number) ?? 0),
181→									formatProjectName(String(name)),
182→								];
183→							}}
184→							labelFormatter={(label) => label}
185→						/>
186→						<Legend
187→							formatter={(value) => formatProjectName(value)}
188→							wrapperStyle={{ paddingTop: "20px" }}
189→						/>
190→						{topProjects.map((projectPath, index) => (
191→							<Line
192→								key={projectPath}
193→								type="monotone"
194→								dataKey={projectPath}
195→								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
196→								strokeWidth={2}
197→								dot={{ r: 3 }}
198→								activeDot={{ r: 5 }}
199→								connectNulls
