227→								padding: "12px",
228→							}}
229→							formatter={(value, name) => {
230→								if (!name || name === "date" || name === "displayDate")
231→									return null;
232→								return [
233→									currentMetric.formatter((value as number) ?? 0),
234→									formatProjectName(String(name)),
235→								];
236→							}}
237→							labelFormatter={(label) => label}
238→						/>
239→						<Legend
240→							formatter={(value) => formatProjectName(value)}
241→							wrapperStyle={{ paddingTop: "20px" }}
242→						/>
243→						{topProjects.map((projectPath, index) => (
244→							<Area
245→								key={projectPath}
246→								type="monotone"
247→								dataKey={projectPath}
248→								stackId="1"
249→								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
250→								fill={PROJECT_COLORS[index % PROJECT_COLORS.length]}
251→								fillOpacity={0.6}
252→								strokeWidth={2}
253→							/>
254→						))}
255→					</AreaChart>
