  9→	Tooltip,
 10→} from "recharts";
 11→
 12→interface TaskClassificationChartProps {
 13→	data: TaskClassification[];
 14→	onTaskTypeClick?: (taskType: string) => void;
 15→}
 16→
 17→const COLORS: Record<string, string> = {
 18→	bug_fix: "#ef4444",
 19→	new_feature: "#3b82f6",
 20→	refactoring: "#8b5cf6",
 21→	tests: "#10b981",
 22→	documentation: "#f59e0b",
 23→	research: "#6366f1",
 24→	unknown: "#6b7280",
 25→};
 26→
 27→const LABELS: Record<string, string> = {
 28→	bug_fix: "Bug Fix",
 29→	new_feature: "New Feature",
 30→	refactoring: "Refactoring",
 31→	tests: "Tests",
 32→	documentation: "Documentation",
 33→	research: "Research",
 34→	unknown: "Unknown",
 35→};
 36→
 37→export function TaskClassificationChart({
 38→	data,
 39→	onTaskTypeClick,
 40→}: TaskClassificationChartProps) {
 41→	const chartData = data.map((item) => ({
 42→		name: LABELS[item.task_type] || item.task_type,
 43→		value: item.count,
 44→		percentage: item.percentage,
 45→		confidence: item.avg_confidence,
 46→		task_type: item.task_type,
 47→	}));
 48→
 49→	const renderCustomLabel = (props: PieLabelRenderProps) => {
 50→		const cx = Number(props.cx) || 0;
 51→		const cy = Number(props.cy) || 0;
 52→		const midAngle = Number(props.midAngle) || 0;
 53→		const innerRadius = Number(props.innerRadius) || 0;
 54→		const outerRadius = Number(props.outerRadius) || 0;
 55→		const percentage =
 56→			Number((props as unknown as Record<string, unknown>).percentage) || 0;
 57→
 58→		const RADIAN = Math.PI / 180;
 59→		const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
 60→		const x = cx + radius * Math.cos(-midAngle * RADIAN);
 61→		const y = cy + radius * Math.sin(-midAngle * RADIAN);
 62→
 63→		if (percentage < 5) return null;
 64→
 65→		return (
 66→			<text
 67→				x={x}
 68→				y={y}
 69→				fill="white"
 70→				textAnchor={x > cx ? "start" : "end"}
 71→				dominantBaseline="central"
 72→				className="text-sm font-semibold"
 73→			>
 74→				{`${percentage.toFixed(1)}%`}
 75→			</text>
 76→		);
 77→	};
 78→
 79→	const CustomTooltip = ({ active, payload }: Record<string, unknown>) => {
 80→		if (active && payload && Array.isArray(payload) && payload.length) {
 81→			const d = (payload[0] as Record<string, unknown>).payload as Record<
 82→				string,
