 11→interface DatePreset {
 12→	label: string;
 13→	getValue: () => { start: string; end: string };
 14→}
 15→
 16→const formatLocalDate = (date: Date): string => {
 17→	const year = date.getFullYear();
 18→	const month = String(date.getMonth() + 1).padStart(2, "0");
 19→	const day = String(date.getDate()).padStart(2, "0");
 20→	return `${year}-${month}-${day}`;
 21→};
 22→
 23→const DATE_PRESETS: DatePreset[] = [
 24→	{
 25→		label: "Last 7 days",
 26→		getValue: () => {
 27→			const end = new Date();
 28→			const start = new Date();
 29→			start.setDate(start.getDate() - 7);
 30→			return { start: formatLocalDate(start), end: formatLocalDate(end) };
 31→		},
 32→	},
 33→	{
 34→		label: "This week",
 35→		getValue: () => {
 36→			const now = new Date();
 37→			const dayOfWeek = now.getDay();
 38→			const start = new Date(now);
 39→			start.setDate(now.getDate() - dayOfWeek);
 40→			return {
 41→				start: formatLocalDate(start),
 42→				end: formatLocalDate(now),
 43→			};
 44→		},
 45→	},
 46→	{
 47→		label: "Last week",
 48→		getValue: () => {
 49→			const now = new Date();
 50→			const dayOfWeek = now.getDay();
 51→			const start = new Date(now);
 52→			start.setDate(now.getDate() - dayOfWeek - 7);
 53→			const end = new Date(start);
 54→			end.setDate(start.getDate() + 6);
 55→			return {
 56→				start: formatLocalDate(start),
 57→				end: formatLocalDate(end),
 58→			};
 59→		},
 60→	},
 61→	{
 62→		label: "Last 30 days",
 63→		getValue: () => {
 64→			const end = new Date();
 65→			const start = new Date();
 66→			start.setDate(start.getDate() - 30);
 67→			return { start: formatLocalDate(start), end: formatLocalDate(end) };
 68→		},
 69→	},
 70→	{
 71→		label: "This month",
 72→		getValue: () => {
 73→			const now = new Date();
 74→			const start = new Date(now.getFullYear(), now.getMonth(), 1);
 75→			return {
 76→				start: formatLocalDate(start),
 77→				end: formatLocalDate(now),
 78→			};
 79→		},
 80→	},
 81→	{
 82→		label: "Last month",
 83→		getValue: () => {
 84→			const now = new Date();
 85→			const start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
 86→			const end = new Date(now.getFullYear(), now.getMonth(), 0);
 87→			return {
 88→				start: formatLocalDate(start),
 89→				end: formatLocalDate(end),
 90→			};
 91→		},
 92→	},
 93→];
 94→
 95→export function DatePicker({
 96→	startDate,
 97→	endDate,
 98→	onStartDateChange,
 99→	onEndDateChange,
100→}: DatePickerProps) {
101→	const [isOpen, setIsOpen] = useState(false);
102→	const [tempStartDate, setTempStartDate] = useState(startDate);
103→	const [tempEndDate, setTempEndDate] = useState(endDate);
104→	const dropdownRef = useRef<HTMLDivElement>(null);
105→
106→	useEffect(() => {
107→		setTempStartDate(startDate);
108→		setTempEndDate(endDate);
109→	}, [startDate, endDate]);
110→
111→	useEffect(() => {
112→		function handleClickOutside(event: MouseEvent) {
113→			if (
114→				dropdownRef.current &&
115→				!dropdownRef.current.contains(event.target as Node)
116→			) {
117→				setIsOpen(false);
118→				setTempStartDate(startDate);
119→				setTempEndDate(endDate);
120→			}
121→		}
122→
123→		if (isOpen) {
124→			document.addEventListener("mousedown", handleClickOutside);
125→			return () =>
126→				document.removeEventListener("mousedown", handleClickOutside);
127→		}
128→	}, [isOpen, startDate, endDate]);
129→
130→	const handleApply = () => {
131→		onStartDateChange(tempStartDate);
132→		onEndDateChange(tempEndDate);
133→		setIsOpen(false);
134→	};
135→
136→	const handlePresetClick = (preset: DatePreset) => {
137→		const { start, end } = preset.getValue();
138→		setTempStartDate(start);
139→		setTempEndDate(end);
140→		onStartDateChange(start);
141→		onEndDateChange(end);
142→		setIsOpen(false);
143→	};
144→
145→	const formatDateRange = () => {
146→		const start = new Date(startDate);
147→		const end = new Date(endDate);
148→		const startStr = start.toLocaleDateString("en-US", {
149→			month: "short",
150→			day: "numeric",
151→		});
152→		const endStr = end.toLocaleDateString("en-US", {
153→			month: "short",
154→			day: "numeric",
155→			year: "numeric",
156→		});
157→		return `${startStr} - ${endStr}`;
158→	};
159→
160→	return (
161→		<div className="relative" ref={dropdownRef}>
162→			<button
163→				type="button"
164→				onClick={() => setIsOpen(!isOpen)}
165→				className="flex items-center gap-2 bg-input border border-border rounded-lg px-4 py-2 hover:bg-hover transition-colors"
166→			>
167→				<Calendar className="h-4 w-4 text-muted" />
168→				<span className="text-sm font-medium text-foreground">
169→					{formatDateRange()}
170→				</span>
171→			</button>
172→
173→			{isOpen && (
174→				<div className="absolute right-0 mt-2 bg-input border border-border rounded-lg z-50 flex overflow-hidden">
175→					<div className="w-40 border-r border-border bg-surface">
176→						{DATE_PRESETS.map((preset) => (
177→							<button
178→								key={preset.label}
179→								type="button"
180→								onClick={() => handlePresetClick(preset)}
181→								className="w-full text-left px-4 py-2 text-sm text-foreground hover:bg-accent-light hover:text-accent-text transition-colors"
182→							>
183→								{preset.label}
184→							</button>
185→						))}
186→					</div>
187→
188→					<div className="p-4 w-64">
189→						<div className="space-y-3">
190→							<div>
191→								<label className="block text-xs font-medium text-muted mb-1">
192→									Start date
193→								</label>
194→								<input
195→									type="date"
196→									value={tempStartDate}
197→									onChange={(e) => setTempStartDate(e.target.value)}
198→									max={tempEndDate}
199→									className="w-full px-3 py-2 text-sm border border-border rounded-md bg-input text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
200→								/>
201→							</div>
202→
203→							<div>
204→								<label className="block text-xs font-medium text-muted mb-1">
205→									End date
206→								</label>
207→								<input
208→									type="date"
209→									value={tempEndDate}
210→									onChange={(e) => setTempEndDate(e.target.value)}
211→									min={tempStartDate}
212→									max={new Date().toISOString().split("T")[0]}
213→									className="w-full px-3 py-2 text-sm border border-border rounded-md bg-input text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
214→								/>
215→							</div>
216→
217→							<div className="pt-2">
218→								<button
219→									type="button"
220→									onClick={handleApply}
221→									className="w-full px-4 py-2 bg-accent text-accent-foreground text-sm font-medium rounded-md hover:bg-accent-hover transition-colors"
222→								>
223→									Apply
224→								</button>
225→							</div>
226→						</div>
227→					</div>
228→				</div>
229→			)}
230→		</div>
231→	);
232→}
