 91→/** Extract a short summary from content for the collapsed label */
 92→function contentSummary(content: unknown): string {
 93→	if (typeof content === "string") {
 94→		return content.slice(0, 100);
 95→	}
 96→	if (Array.isArray(content)) {
 97→		const first = content[0] as Record<string, unknown> | undefined;
 98→		if (first?.type === "tool_result") {
 99→			const text =
100→				typeof first.content === "string"
101→					? first.content
102→					: JSON.stringify(first.content);
103→			return `tool_result: ${text.slice(0, 80)}`;
104→		}
105→		if (first?.type === "text" && first?.text) {
106→			return String(first.text).slice(0, 100);
107→		}
108→	}
109→	return "";
110→}
