127→		) {
128→			return null;
129→		}
130→	}
131→
132→	// Handle summary entries
133→	if ("role" in entry && entry.role === "summary") {
134→		const summaryText = "summary" in entry ? String(entry.summary) : "";
135→		return (
136→			<div
137→				id={anchorId}
