161→		return (
162→			<CollapsedEntry
163→				icon={Settings}
164→				label="System"
165→				summary={systemContent.slice(0, 100)}
166→				anchorId={anchorId}
167→				className={className}
168→			>
169→				<p className="text-sm text-foreground whitespace-pre-wrap leading-relaxed font-mono py-2">
170→					{systemContent}
171→				</p>
172→			</CollapsedEntry>
173→		);
174→	}
175→
176→	// Handle user messages (both role-based and type-based)
177→	const isUserMessage =
178→		("role" in entry && entry.role === "user") ||
179→		("type" in entry && (entry as Record<string, unknown>).type === "user");
180→
181→	if (isUserMessage) {
182→		const entryAny = entry as Record<string, unknown>;
183→
184→		// Type-based entries have content nested in message.content
185→		const content =
186→			(entryAny.message as Record<string, unknown> | undefined)?.content ||
187→			entryAny.content ||
188→			entryAny.text ||
189→			"";
190→
191→		// Tool result entries — collapsed with wrench icon
192→		if (entryAny.toolUseResult != null) {
193→			const toolResult = entryAny.toolUseResult as Record<string, unknown>;
194→			const toolType = (toolResult.type as string) || "tool";
195→
196→			// Check for errors: exit code, stderr, interrupted, or is_error on content items
197→			const hasNonZeroExit =
198→				typeof toolResult.code === "number" && toolResult.code !== 0;
199→			const hasStderr =
200→				typeof toolResult.stderr === "string" && toolResult.stderr.length > 0;
201→			const wasInterrupted = toolResult.interrupted === true;
202→			const contentHasError =
203→				Array.isArray(content) &&
204→				content.some((item: Record<string, unknown>) => item?.is_error);
205→			const isError =
206→				hasNonZeroExit || hasStderr || wasInterrupted || contentHasError;
207→
208→			return (
209→				<CollapsedEntry
210→					icon={Wrench}
211→					label={`Tool Result (${toolType})`}
212→					summary={contentSummary(content)}
213→					variant={isError ? "error" : "success"}
214→					anchorId={anchorId}
215→					className={className}
216→				>
217→					<div className="py-2">
218→						<MessageContent content={content as string | Content[]} />
219→					</div>
220→				</CollapsedEntry>
221→			);
222→		}
223→
224→		// Meta entries — collapsed with settings icon
225→		if (entryAny.isMeta || entryAny.isCompactSummary) {
226→			return (
227→				<CollapsedEntry
228→					icon={Settings}
229→					label={entryAny.isCompactSummary ? "Compact Summary" : "Meta"}
230→					summary={contentSummary(content)}
231→					anchorId={anchorId}
232→					className={className}
233→				>
234→					<div className="py-2">
235→						<MessageContent content={content as string | Content[]} />
236→					</div>
237→				</CollapsedEntry>
238→			);
239→		}
240→
241→		// Content that's all tool_result items — collapsed with wrench icon
242→		if (Array.isArray(content)) {
243→			const allToolResults = content.every(
244→				(item: Record<string, unknown>) => item?.type === "tool_result",
245→			);
246→			if (allToolResults) {
247→				const hasError = content.some(
248→					(item: Record<string, unknown>) => item?.is_error,
249→				);
250→				return (
251→					<CollapsedEntry
252→						icon={Wrench}
253→						label={`Tool Results (${content.length})`}
254→						summary={contentSummary(content)}
255→						variant={hasError ? "error" : "success"}
256→						anchorId={anchorId}
257→						className={className}
258→					>
259→						<div className="py-2">
260→							<MessageContent content={content as Content[]} />
261→						</div>
262→					</CollapsedEntry>
263→				);
264→			}
265→		}
266→
267→		// Check for slash command
268→		const isSlashCommand =
269→			typeof content === "string" && isSlashCommandMessage(content);
270→		const slashCommandInfo = isSlashCommand ? parseSlashCommand(content) : null;
271→
272→		return (
273→			<div id={anchorId} className={cn("flex gap-4 scroll-mt-6", className)}>
274→				<div className="flex-shrink-0">
275→					<div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center">
276→						<User className="w-5 h-5 text-white" />
277→					</div>
278→				</div>
279→				<div className="flex-1 min-w-0 bg-card border border-border rounded-lg p-4 shadow-sm">
280→					<div className="flex items-center gap-2 mb-3">
281→						<span className="text-sm font-semibold text-foreground">User</span>
282→						{!!(entry as Record<string, unknown>).timestamp && (
283→							<span className="text-xs text-muted-foreground">
284→								{new Date(
285→									String((entry as Record<string, unknown>).timestamp),
286→								).toLocaleTimeString()}
287→							</span>
288→						)}
289→					</div>
290→
291→					{isSlashCommand && slashCommandInfo ? (
292→						<div className="space-y-2">
293→							{slashCommandInfo.commandMessage && (
294→								<div className="inline-block px-3 py-1 bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200 rounded-md text-sm font-mono">
295→									{slashCommandInfo.commandMessage}
296→								</div>
297→							)}
298→							{slashCommandInfo.commandName && (
299→								<div className="text-sm text-muted-foreground">
300→									<span className="font-semibold">Command:</span>{" "}
301→									<code className="bg-muted px-2 py-0.5 rounded">
302→										{slashCommandInfo.commandName}
303→									</code>
304→								</div>
305→							)}
306→							{slashCommandInfo.commandArgs && (
307→								<div className="text-sm text-muted-foreground">
308→									<span className="font-semibold">Args:</span>{" "}
309→									<code className="bg-muted px-2 py-0.5 rounded">
310→										{slashCommandInfo.commandArgs}
311→									</code>
312→								</div>
313→							)}
314→						</div>
315→					) : (
316→						<MessageContent content={content as string | Content[]} />
317→					)}
318→				</div>
319→			</div>
320→		);
321→	}
322→
323→	// Handle assistant messages (both role-based and type-based)
324→	const isAssistantMessage =
325→		("role" in entry && entry.role === "assistant") ||
326→		("type" in entry &&
327→			(entry as Record<string, unknown>).type === "assistant");
328→
329→	if (isAssistantMessage) {
330→		const entryAny = entry as Record<string, unknown>;
331→		const assistantContent =
332→			(entryAny.message as Record<string, unknown> | undefined)?.content ||
333→			entryAny.content ||
334→			entryAny.text ||
335→			"";
336→
337→		return (
338→			<div id={anchorId} className={cn("flex gap-4 scroll-mt-6", className)}>
339→				<div className="flex-shrink-0">
340→					<div className="w-8 h-8 rounded-full bg-gradient-to-br from-purple-600 to-blue-600 flex items-center justify-center">
341→						<Bot className="w-5 h-5 text-white" />
342→					</div>
343→				</div>
344→				<div className="flex-1 min-w-0 bg-card border border-border rounded-lg p-4 shadow-sm">
345→					<div className="flex items-center gap-2 mb-3">
346→						<span className="text-sm font-semibold text-foreground">
347→							Assistant
348→						</span>
349→						{!!(entry as Record<string, unknown>).timestamp && (
350→							<span className="text-xs text-muted-foreground">
351→								{new Date(
352→									String((entry as Record<string, unknown>).timestamp),
353→								).toLocaleTimeString()}
354→							</span>
355→						)}
356→					</div>
357→					<MessageContent content={assistantContent as string | Content[]} />
358→				</div>
359→			</div>
360→		);
361→	}
362→
363→	// Handle system messages (type-based)
364→	const isSystemMessage =
365→		("role" in entry && entry.role === "system") ||
366→		("type" in entry && (entry as Record<string, unknown>).type === "system");
367→
368→	if (isSystemMessage) {
369→		const entryAny = entry as Record<string, unknown>;
370→		const systemContent =
371→			(entryAny.content as string) || (entryAny.text as string) || "";
372→		const subtype = (entryAny.subtype as string) || "system";
373→		return (
374→			<CollapsedEntry
375→				icon={Settings}
376→				label={`System (${subtype})`}
377→				summary={systemContent.slice(0, 100)}
378→				anchorId={anchorId}
379→				className={className}
380→			>
381→				<p className="text-sm text-foreground whitespace-pre-wrap leading-relaxed font-mono py-2">
382→					{systemContent}
383→				</p>
384→			</CollapsedEntry>
385→		);
386→	}
387→
388→	return null;
389→}
