  6→interface ToolInvocationProps {
  7→	toolName: string;
  8→	input: Record<string, unknown>;
  9→	result?: {
 10→		content: string | Array<{ type: string; text?: string; source?: unknown }>;
 11→		is_error?: boolean;
 12→	};
 13→	className?: string;
 14→}
 15→
 16→export function ToolInvocation({
 17→	toolName,
 18→	input,
 19→	result,
 20→	className,
 21→}: ToolInvocationProps) {
 22→	const [isExpanded, setIsExpanded] = useState(false);
 23→
 24→	// Format input for display
 25→	const formatInput = () => {
 26→		const keys = Object.keys(input);
 27→		if (keys.length === 0) return "No parameters";
 28→
 29→		const important = keys.slice(0, 2);
 30→		const summary = important
 31→			.map((key) => {
 32→				const value = input[key];
 33→				if (typeof value === "string" && value.length > 50) {
 34→					return `${key}: "${value.slice(0, 50)}..."`;
 35→				}
 36→				if (typeof value === "string") {
 37→					return `${key}: "${value}"`;
 38→				}
 39→				return `${key}: ${JSON.stringify(value)}`;
 40→			})
 41→			.join(", ");
 42→
 43→		return keys.length > 2 ? `${summary}, +${keys.length - 2} more` : summary;
 44→	};
 45→
 46→	// Format result content
 47→	const getResultContent = (): string => {
 48→		if (!result) return "";
 49→
 50→		if (typeof result.content === "string") {
 51→			return result.content;
 52→		}
 53→
 54→		if (Array.isArray(result.content)) {
 55→			return result.content
 56→				.map((item) => item.text || JSON.stringify(item))
 57→				.join("\n");
 58→		}
 59→
 60→		return JSON.stringify(result.content, null, 2);
 61→	};
 62→
 63→	const hasResult = result?.content;
 64→	const isError = result?.is_error;
 65→
 66→	return (
 67→		<div
 68→			className={cn(
 69→				"border rounded-lg overflow-hidden",
 70→				isError
 71→					? "border-red-300 bg-red-50 dark:border-red-800 dark:bg-red-950"
 72→					: "border-border bg-muted/30",
 73→				className,
 74→			)}
 75→		>
 76→			<button
 77→				onClick={() => setIsExpanded(!isExpanded)}
 78→				className="w-full px-4 py-3 flex items-center gap-2 text-left hover:bg-muted/50 transition-colors min-w-0"
 79→			>
 80→				{isExpanded ? (
 81→					<ChevronDown className="w-4 h-4 text-muted-foreground flex-shrink-0" />
 82→				) : (
 83→					<ChevronRight className="w-4 h-4 text-muted-foreground flex-shrink-0" />
 84→				)}
 85→				{isError ? (
 86→					<AlertCircle className="w-4 h-4 text-red-500 flex-shrink-0" />
 87→				) : (
 88→					<Terminal className="w-4 h-4 text-blue-500 flex-shrink-0" />
 89→				)}
 90→				<span
 91→					className={cn(
 92→						"font-mono text-sm font-semibold",
 93→						isError ? "text-red-700 dark:text-red-300" : "text-foreground",
 94→					)}
 95→				>
 96→					{toolName}
 97→				</span>
 98→				<span className="text-xs text-muted-foreground truncate flex-1">
 99→					{formatInput()}
100→				</span>
101→			</button>
102→
103→			{isExpanded && (
104→				<div className="px-4 pb-4 space-y-3">
105→					{/* Tool Input */}
106→					<div>
107→						<h4 className="text-xs font-semibold text-muted-foreground mb-2">
108→							Input Parameters
109→						</h4>
110→						<CodeBlock code={JSON.stringify(input, null, 2)} language="json" />
111→					</div>
112→
113→					{/* Tool Result */}
114→					{hasResult && (
115→						<div>
116→							<h4
117→								className={cn(
118→									"text-xs font-semibold mb-2",
119→									isError
120→										? "text-red-700 dark:text-red-300"
121→										: "text-muted-foreground",
122→								)}
123→							>
124→								{isError ? "Error Output" : "Output"}
125→							</h4>
126→							<CodeBlock
127→								code={getResultContent()}
128→								language="text"
129→								className={
130→									isError
131→										? "border-2 border-red-300 dark:border-red-800"
132→										: undefined
133→								}
134→							/>
135→						</div>
136→					)}
137→				</div>
138→			)}
139→		</div>
140→	);
141→}
