 18→
 19→const CHART_HEIGHT = 100;
 20→const LANE_HEIGHT = 28;
 21→const LANE_TOP_PAD = 8;
 22→const DOT_RADIUS = 4;
 23→const LEFT_MARGIN = 40; // match token chart
 24→
 25→const lanes: {
 26→	category: ToolActivityPoint["category"];
 27→	label: string;
 28→	y: number;
 29→}[] = [
 30→	{ category: "tool", label: "Tools", y: LANE_TOP_PAD + LANE_HEIGHT * 0.5 },
 31→	{ category: "skill", label: "Skills", y: LANE_TOP_PAD + LANE_HEIGHT * 1.5 },
 32→	{
 33→		category: "subagent",
 34→		label: "Agents",
 35→		y: LANE_TOP_PAD + LANE_HEIGHT * 2.5,
 36→	},
 37→];
 38→
 39→export function ToolActivityChart({
 40→	data,
 41→	totalMessages,
 42→	activeMessageIndex,
 43→	onClickMessage,
 44→	className,
 45→}: ToolActivityChartProps) {
 46→	const containerRef = useRef<HTMLDivElement>(null);
 47→	const [chartWidth, setChartWidth] = useState(400);
 48→
 49→	useEffect(() => {
 50→		const el = containerRef.current;
 51→		if (!el) return;
 52→		const observer = new ResizeObserver((entries) => {
 53→			const entry = entries[0];
 54→			if (entry) setChartWidth(entry.contentRect.width);
 55→		});
 56→		observer.observe(el);
 57→		return () => observer.disconnect();
 58→	}, []);
 59→
 60→	const drawWidth = chartWidth - LEFT_MARGIN;
 61→
 62→	const counts = useMemo(() => {
 63→		const tools = data.filter((d) => d.category === "tool").length;
 64→		const skills = data.filter((d) => d.category === "skill").length;
 65→		const subagents = data.filter((d) => d.category === "subagent").length;
 66→		const errors = data.filter((d) => d.isError).length;
 67→		return { tools, skills, subagents, errors };
 68→	}, [data]);
 69→
 70→	const handleClick = useCallback(
 71→		(e: React.MouseEvent<SVGSVGElement>) => {
 72→			if (totalMessages === 0 || data.length === 0) return;
 73→
 74→			const svg = e.currentTarget;
 75→			const rect = svg.getBoundingClientRect();
 76→			const px = e.clientX - rect.left - LEFT_MARGIN;
 77→			const fraction = px / drawWidth;
 78→
 79→			let closest = data[0];
 80→			let closestDist = Infinity;
 81→			for (const d of data) {
 82→				const dx = Math.abs(d.messageIndex / totalMessages - fraction);
 83→				if (dx < closestDist) {
 84→					closestDist = dx;
 85→					closest = d;
 86→				}
 87→			}
 88→			if (closest) {
 89→				onClickMessage(closest.messageIndex);
 90→			}
 91→		},
 92→		[data, totalMessages, drawWidth, onClickMessage],
 93→	);
 94→
 95→	if (data.length === 0) {
 96→		return (
 97→			<div className={cn("text-xs text-muted text-center py-4", className)}>
 98→				No tool activity
 99→			</div>
100→		);
101→	}
102→
103→	const cursorX =
104→		LEFT_MARGIN +
105→		(totalMessages > 0 ? activeMessageIndex / totalMessages : 0) * drawWidth;
106→
107→	return (
108→		<div className={className}>
109→			<div className="text-xs font-medium text-muted mb-2">Tool Activity</div>
110→
111→			<div className="flex gap-3 text-[10px] text-muted mb-1">
112→				<span>{counts.tools} tools</span>
113→				<span>{counts.skills} skills</span>
114→				<span>{counts.subagents} subagents</span>
115→				{counts.errors > 0 && (
116→					<span className="text-red-400">{counts.errors} errors</span>
117→				)}
118→			</div>
119→
120→			<div ref={containerRef}>
121→				<svg
122→					viewBox={`0 0 ${chartWidth} ${CHART_HEIGHT}`}
123→					className="w-full cursor-pointer"
124→					style={{ height: `${CHART_HEIGHT}px` }}
125→					onClick={handleClick}
126→				>
127→					{/* Lane labels + separators */}
128→					{lanes.map((lane, idx) => (
129→						<g key={lane.category}>
130→							<line
131→								x1={LEFT_MARGIN}
132→								y1={LANE_TOP_PAD + idx * LANE_HEIGHT}
133→								x2={chartWidth}
134→								y2={LANE_TOP_PAD + idx * LANE_HEIGHT}
135→								stroke="currentColor"
136→								strokeWidth="0.5"
137→								className="text-border"
138→							/>
139→							<text
140→								x={LEFT_MARGIN - 4}
141→								y={lane.y + 3}
142→								textAnchor="end"
143→								className="fill-muted"
144→								fontSize="9"
145→							>
146→								{lane.label}
147→							</text>
148→						</g>
149→					))}
150→					{/* Bottom border */}
151→					<line
152→						x1={LEFT_MARGIN}
153→						y1={LANE_TOP_PAD + lanes.length * LANE_HEIGHT}
154→						x2={chartWidth}
155→						y2={LANE_TOP_PAD + lanes.length * LANE_HEIGHT}
156→						stroke="currentColor"
157→						strokeWidth="0.5"
158→						className="text-border"
159→					/>
160→
161→					{/* Activity dots */}
162→					{data.map((d, i) => {
163→						const x =
164→							LEFT_MARGIN + (d.messageIndex / totalMessages) * drawWidth;
165→						const lane = lanes.find((l) => l.category === d.category);
166→						if (!lane) return null;
167→
168→						return (
169→							<circle
170→								key={i}
171→								cx={x}
172→								cy={lane.y}
173→								r={DOT_RADIUS}
174→								className={
175→									d.isError
176→										? "fill-red-400/80 hover:fill-red-500"
177→										: d.category === "tool"
178→											? "fill-green-400/80 hover:fill-green-500"
179→											: d.category === "skill"
180→												? "fill-purple-400/80 hover:fill-purple-500"
181→												: "fill-orange-400/80 hover:fill-orange-500"
182→								}
183→							/>
184→						);
185→					})}
186→
187→					{/* Cursor line */}
188→					<line
189→						x1={cursorX}
190→						y1="0"
191→						x2={cursorX}
192→						y2={CHART_HEIGHT}
193→						stroke="currentColor"
194→						strokeWidth="1"
195→						className="text-foreground"
196→						strokeDasharray="4,2"
197→					/>
198→				</svg>
199→			</div>
200→
201→			{/* Legend */}
202→			<div className="flex items-center gap-3 mt-1.5 text-[10px] text-muted">
203→				<div className="flex items-center gap-1">
204→					<div className="w-2 h-2 rounded-full bg-green-400" />
205→					<span>Tools</span>
206→				</div>
207→				<div className="flex items-center gap-1">
208→					<div className="w-2 h-2 rounded-full bg-purple-400" />
209→					<span>Skills</span>
210→				</div>
211→				<div className="flex items-center gap-1">
212→					<div className="w-2 h-2 rounded-full bg-orange-400" />
213→					<span>Subagents</span>
214→				</div>
215→				<div className="flex items-center gap-1">
216→					<div className="w-2 h-2 rounded-full bg-red-400" />
217→					<span>Error</span>
218→				</div>
219→			</div>
220→		</div>
221→	);
222→}
